#include <cstring>
#include <algorithm>

void safeCopy(char* dest, const char* src, size_t destSize) {
  strncpy(dest, src, destSize - 1); // Compliant: bounded copy
  dest[destSize - 1] = '\0';
}

#include <vector>

void safeArrayAccess(const std::vector<int>& arr, size_t index) {
  if (index < arr.size()) { // Compliant: bounds checking
    int value = arr[index];
  }
}

void safeBoundedWrite(char* buffer, size_t bufferSize) {
  size_t maxWrite = std::min(bufferSize, static_cast<size_t>(1000));
  for (size_t i = 0; i < maxWrite; ++i) {
    buffer[i] = 'A'; // Compliant: bounded access
  }
}
